<script>
(function(){var root=document.querySelector('.dsm');if(!root)return;var tabs=[].slice.call(root.querySelectorAll('[data-dsm-tab]'));var panels=[].slice.call(root.querySelectorAll('[data-dsm-tab-panel]'));function activate(name){tabs.forEach(function(tab){var active=tab.getAttribute('data-dsm-tab')===name;tab.classList.toggle('is-active',active);tab.setAttribute('aria-selected',active?'true':'false')});panels.forEach(function(panel){panel.classList.toggle('is-active',panel.getAttribute('data-dsm-tab-panel')===name)});if(history.replaceState)history.replaceState(null,'','#'+name)}tabs.forEach(function(tab){tab.addEventListener('click',function(){activate(tab.getAttribute('data-dsm-tab'))})});var initial=(location.hash||'').replace('#','');if(initial&&tabs.some(function(tab){return tab.getAttribute('data-dsm-tab')===initial}))activate(initial)})();
</script>